vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

uvs = (vUv-0.5)*2 + vec2(q11,q12);
uvb = (vUv-0.5)*0.5 + 0.5 - (vec2(q11,q12)-0.5)*0.5;

c = pow(fract(q1),0.5);
uv_i = mix(uvs,vUv,c);
uv_ii = mix(vUv,uvb,c);

ret = (texture(sampler_fc_main,uv_i)*c+texture(sampler_fc_main,uv_ii)*(1-c));


  fragColor = ret;
}
